var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨! 대체 무슨 짓이야!","JPN":"おじさん！　いったいどういうこと！？","ENG":"Mr. Mason, what were you thinking?!","TWN":"大叔！你這是在幹嘛啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"수송기에서 그대로 던져 버리다니, 죽는 줄 알았잖아!","JPN":"輸送機からそのまま投げ飛ばすなんて、死ぬかと思ったじゃん！","ENG":"You just threw us out of the ship! We could have died!","TWN":"竟然就那樣從貨機上一躍而下，我還以為你們會死掉！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 덕분에 침식체의 위협에서 안전해졌지.","JPN":"だがおかげで侵食体の脅威から守られたぞ。","ENG":"Yet here we are, safe and sound from the threat of the C.O.s.","TWN":"起碼我們脫離侵蝕體的威脅啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"애초에 너희들이니까 할 수 있다고 생각한 거야.","JPN":"あんたらのことだから最初からできると信じてたんだよ。","ENG":"I believed in you guys.","TWN":"因為是你們，我們才敢放心跳的嘛！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"음? 잠깐, 저 빛은 뭐지?","JPN":"うん？　待て、あの光は何だ？","ENG":"Huh? What’s that light?","TWN":"嗯？先等一下，那個光是怎麼回事？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"말 돌리지 말고……!","JPN":"ねえ、話を逸らさない……！","ENG":"Don’t try to switch the subject—","TWN":"不要轉移話題……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"엎드려!","JPN":"伏せろ！","ENG":"Get down!","TWN":"趴下！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야?","JPN":"な、何？","ENG":"W-what’s that?","TWN":"幹嘛？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대령! 설마 저건가?","JPN":"大佐！　まさかアレか？","ENG":"Colonel, is that it?!","TWN":"上校！是那個嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……그래. 등대의 빛인 것 같아.","JPN":"……ああ。灯台の光のようだ。","ENG":"... Yes, it must be from the Lighthouse.","TWN":"……沒錯，應該是燈塔的光。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 위력만 봐선 함선급 광선 무기에 더 가까운 것 같은데요.","JPN":"ですが、威力だけ見れば艦船級の光線兵器に近いようですが。","ENG":"But that almost looks like a laser shot from a battleship.","TWN":"但威力感覺接近艦船等級的光束武器？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"등대라는 게 원래 저런 고출력 광선을 발사하는 물건인가요?","JPN":"灯台というのは元々あんな高出力光線を放つものなんですか？","ENG":"Is that what the Lighthouse is supposed to do, emit a high-power beam?","TWN":"燈塔原本就會發射高輸出的光束嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아니. 내가 봤던 등대는 평범한 신호기였어.","JPN":"いや、俺が見た灯台は普通の信号機だった。","ENG":"No, the Lighthouse I saw was a common signal transmitter.","TWN":"不，我看過的燈塔就只是一個單純的信號器。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍도 뚫을 수 있는 특별한 신호를 발산하긴 했지만, 이 정도로 강력하지는 않았는데…….","JPN":"次元の暴風を突破できる特別な信号を発信していたが、\\nこれほど強力ではなかったはず……","ENG":"The signal was strong enough to make it through the storm, but not that strong...","TWN":"雖然是可以發射穿透次元風暴的特殊信號，但威力不至於這麼大……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……이거 불길한 예상이 떠오르는군.","JPN":"……これは嫌な予感しかしないな。","ENG":"I have a bad feeling about this.","TWN":"……我有種不好的預感！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"불길한 예상?","JPN":"嫌な予感？","ENG":"A bad feeling?","TWN":"不好的預感？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래. 그 샬롯이라는 아가씨가 등대를 찾고 있었다고 했지?","JPN":"ああ。あのシャーロットという嬢ちゃんが灯台を探していたと言ってたよな？","ENG":"Yes. Carlota was looking for the Lighthouse, right?","TWN":"對，那個叫夏洛特的丫頭不是在找燈塔嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"등대의 저 비정상적인 출력은 그 아가씨가 가지고 간 노바급 리액터에서 나오는 걸지도 몰라.","JPN":"灯台のあの異常な出力は、あの嬢ちゃんに持っていかれた\\nノヴァ級リアクターから放たれたものかもしれない。","ENG":"Maybe she used the Nova-Class Reactor on the Lighthouse. Hence the crazy beam.","TWN":"我懷疑燈塔不正常的輸出，是來自那丫頭拿走的諾瓦反應爐！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"무슨 소리인가 했더니…….","JPN":"何を言い出すかと思ったら……","ENG":"Oh, for God’s sake...","TWN":"我還以為你要發表什麼高見……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"메이슨 씨, 등대는 이동포대 같은 게 아니야.","JPN":"メイソンさん、灯台は移動式砲台みたいなもんじゃないぞ。","ENG":"Mr. Mason, the Lighthouse was not designed to be a weapon.","TWN":"梅森，燈塔不是移動砲台好嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"노바급 리액터를 등대에 결합해서 무기로 만든다고 해도 전략적으로는 아무 의미도 없다고.","JPN":"ノヴァ級リアクターを灯台に接続して武器にしたとしても、\\n戦略的には何の意味もないんだよ。","ENG":"There is no tactical advantage in weaponizing the Lighthouse by attaching the Nova-Class Reactor.","TWN":"就算真的可以將諾瓦反應爐裝在燈塔上改造成武器，但就戰略上而言根本毫無意義。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"무기로서는 그렇겠지. 하지만…….","JPN":"武器としてはそうだろう。だが……","ENG":"Maybe not as a weapon. But...","TWN":"若是當成武器確實沒意義，但是……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇군요. 애초에 무기가 아니라 등대 자체의 목적을 극대화하기 위해서일지도 모릅니다.","JPN":"なるほど。そもそも武器ではなく灯台そのものの役割を強大化するためかもしれませんね。","ENG":"I see. Maybe she used the reactor to amplify the original functionality of the Lighthouse.","TWN":"原來如此！很可能一開始的目的就不是要打造成武器，而是要將燈塔本身的功能極大化。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"등대 자체의 목적이라고?","JPN":"灯台そのものの役割だって？","ENG":"The original functionality of the Lighthouse?","TWN":"燈塔本身的功能？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네. 등대란 원래 길을 잃은 자들에게 빛을 비춰 안내하는 역할을 하니 말입니다.","JPN":"はい。灯台とは、本来道に迷った者に光を照らして案内するためのものです。","ENG":"Yes, the Lighthouse is supposed to guide lost people with its light.","TWN":"對，燈塔本身的功能就是要為那些迷路的人照亮方向。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 저렇게 강력해진 등대라면……. 대체 어디에서 어떤 존재를 끌어 오기 위한 걸까요?","JPN":"しかし、あれほど強力な灯台となれば……\\nいったいどこからどんな存在を引き寄せるためのものなんでしょう？","ENG":"But I wonder, what will the amplified light bring in, and from where?","TWN":"但如果燈塔的光束變得那麼強……那會從哪裡引來哪些東西呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……제이나!","JPN":"……ジェイナ！","ENG":"... Jaina!","TWN":"……婕娜！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 네. 워커 씨…… 아니, 대령님.","JPN":"あ、はい、ウォーカーさん……いえ、大佐。","ENG":"Oh, yes, Mr. Walker...I mean, Colonel.","TWN":"喔，是，沃克……不對，是上校。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"당장 등대를 파괴해야 돼. 이 거리에서 요격할 수 있겠나?","JPN":"今すぐ灯台を破壊しなければならない。この距離で迎撃できそうか？","ENG":"We have to destroy the Lighthouse right now. Can you hit it from here?","TWN":"必須立刻毀掉燈塔，你從這個距離有辦法打中它嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"장거리 저격 말인가요……?","JPN":"長距離狙撃ということですか……？","ENG":"A long-range attack?","TWN":"是指要遠距離狙擊嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"해 본 적은 없지만……. 왠지 할 수 있을 것 같은 기분이 들어요.","JPN":"やったことはありませんが……なぜかできそうな気がします。","ENG":"I haven’t tried before... but I feel like I can do it.","TWN":"我是沒試過……但總覺得應該可以。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"해 보겠습니다!","JPN":"やってみます！","ENG":"I will try!","TWN":"我試試看！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"성공했나?!","JPN":"成功したか！？","ENG":"Did that work?","TWN":"成功了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아니. 아쉽지만 막힌 모양이야.","JPN":"いや、残念だが止められたようだ。","ENG":"No, the shot was blocked.","TWN":"沒有，很可惜，被擋下來。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……저 도둑 아가씨에게 말이지.","JPN":"……あの泥棒猫のお嬢さんにな。","ENG":"By that thieving girl.","TWN":"……就是那個小偷騎士幹的好事！"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"샬롯! 대체 뭘 꾸미고 있는 거야?","JPN":"シャーロット！　いったい何を企んでるの？","ENG":"Carlota! What are you planning?","TWN":"夏洛特！她到底想做什麼？"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"등대가 기동되었습니다, 전하.","JPN":"灯台が起動しました、殿下。","ENG":"The Lighthouse is activated, Your Highness.","TWN":"殿下，燈塔啟動了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 그러면 이제 기다리는 일만 남았군.","JPN":"ああ。あとは待つのみか。","ENG":"Yes, then we will wait.","TWN":"嗯，接下來能做的就只有等待了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하, 질문을 허락해 주시겠습니까?","JPN":"殿下、質問をお許しいただけますでしょうか？","ENG":"Your Highness, may I ask you a question?","TWN":"殿下，可否允許我問一個問題？"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"반역자의 딸이 감히 내게 질문을 하다니 건방지기 짝이 없군.","JPN":"反逆者の娘ごときが私に質問をするとは、身の程知らずだな。","ENG":"How dare you. The daughter of the traitor has a question for me.","TWN":"逆賊之女膽敢問我問題，真是放肆！"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"허나 오늘은 그대가 세운 공을 생각해 허락해 주지. 말해 봐라.","JPN":"だが今日は貴様の功績に免じて許してやろう。言ってみろ。","ENG":"But you did well today, so I will allow it. Speak.","TWN":"不過看在今天你立下大功的份上，就允許你發問吧！"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"정말…… 이런 일을 하면 제국이 다시 일어설 수 있습니까?","JPN":"本当に……このようなことで帝国を再建できるのでしょうか？","ENG":"Would this... really help to rebuild the Empire?","TWN":"這麼做……真的可以讓帝國再次復興起來嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"제국과 함께 사라져 버린 제 가문과, 부모님을 구원할 수 있습니까?","JPN":"帝国と共に消えてしまった私の一族と両親は、救われるのでしょうか？","ENG":"Would it actually save my lost family and parents?","TWN":"當初和帝國一起消失的家族和父母，真的能夠得到救贖嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그동안 제가 봐 온 게임의 끝은…….","JPN":"これまで私が見てきたゲームの終わりは……","ENG":"Every ending to the game I've seen so far...","TWN":"過去我看到的遊戲結局……"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"몰락한 가문의 후예답게 어리석은 질문이구나, 샬롯 마르티네즈.","JPN":"没落した一族の末裔らしく愚かな質問だな、シャーロット・マルチネス。","ENG":"That was a very stupid question, Carlota Martinez. Which would be expected from the heir of a fallen house.","TWN":"不愧是沒落家族的後裔，問的問題也很愚蠢，夏洛特 馬汀尼茲。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이 게임은 구원을 위한 것도, 명예를 위한 것도 아니다.","JPN":"このゲームは救いのためでも、名誉のためでもない。","ENG":"This game is neither for honor nor for redemption.","TWN":"這個遊戲的目的不是救贖，也不是榮譽。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이 게임을 하는 것은 그것이 의무이기 때문이지.","JPN":"このゲームを行うのは、それが義務だからだ。","ENG":"We play this game because it is our duty.","TWN":"是基於義務而進行的。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"귀족도, 반역자도, 심지어 황족도 벗어날 수 없는 의무.","JPN":"貴族も反逆者も、皇族すらも逃れられない義務。","ENG":"None of us is free from the duty, whether you’re a noble, a traitor, or a royal.","TWN":"無論是貴族、逆賊、甚至是皇族，都無法擺脫這個義務。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"바로 복수의 의무다.","JPN":"まさに復讐の義務だ。","ENG":"The duty of vengeance.","TWN":"也就是報仇的義務。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"가문을 구원하고 싶은가?","JPN":"一族を救いたいか？","ENG":"Do you want to save your family?","TWN":"你想使家族得到救贖嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그렇다면 네게 주어진 의무를 다해라, 샬롯 마르티네즈.","JPN":"ならば貴様に与えられた義務を果たせ、シャーロット・マルチネス。","ENG":"Then answer to your duty, Carlota Martinez.","TWN":"那就完成交代給你的義務，夏洛特 馬汀尼茲！"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……명심하겠습니다.","JPN":"……肝に銘じます。","ENG":"... I will, Your Highness.","TWN":"……我會銘記在心。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"제국을 위해……","JPN":"帝国のために……","ENG":"For the Empire...","TWN":"為了帝國……"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L35_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"가문을 위해……","JPN":"一族のために……","ENG":"For my family...","TWN":"為了家族……"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"나를 위해……","JPN":"己のために……","ENG":"And for myself...","TWN":"為了我……"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"누구도, 여길 지나갈 수는 없다.","JPN":"誰一人として、ここを通すわけにはいかない。","ENG":"I shall not let anyone pass.","TWN":"誰也別想越過這裡。"},"stage":{"bg":"WAREHOUSE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};